Warning: ```bash
sqlite3 staging.db <<'SQL'
BEGIN IMMEDIATE;
PRAGMA user_version;
-- migration statements here
PRAGMA user_version = 6;
COMMIT;
SQL
```
Use a staging file or verified backup before any production SQLite change.

Warning: ```bash
sqlite3 app.db ".backup app.before-delete.db"
sqlite3 app.db <<'SQL'
BEGIN IMMEDIATE;
DELETE FROM sessions WHERE expires_at < datetime('now', '-30 days');
COMMIT;
SQL
```
Use a staging file or verified backup before any production SQLite change.

```bash
#!/usr/bin/env bash
set -euo pipefail
usage() { echo "usage: ${0##*/} --target VALUE [--dry-run] [--json]" >&2; exit 64; }
log() { printf '%s\n' "$*" >&2; }
die() { log "error: $*"; exit 1; }
dry_run=false
json=false
target=""
while [ "$#" -gt 0 ]; do
  case "$1" in
    --target) target=${2:-}; shift 2 ;;
    --dry-run) dry_run=true; shift ;;
    --json) json=true; shift ;;
    -h|--help) usage ;;
    *) die "unknown argument: $1" ;;
  esac
done
[ -n "$target" ] || usage
command -v bash >/dev/null || die "bash is missing"
log "planning ssh config preflight for $target"
if [ "$dry_run" = true ]; then
  log "dry-run: would run sshd -t"
  exit 0
fi
printf '%s\t%s\n' "target" "$target"
```
This gives the tool a clear argument contract, stderr logging, dry-run behavior, and explicit nonzero exits for invalid input.

